@using sv_6db0c24234034a40aab2695891c22120.Services

<h4 class="mb-4">Profile Settings</h4>

@if (_showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Profile saved successfully!
        <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
    </div>
}

<div class="row">
    <div class="col-md-8">
        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" @bind:event="oninput"
                   @bind:after="MarkChanged" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="_email" @bind:event="oninput"
                   @bind:after="MarkChanged" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="4" @bind="_bio" @bind:event="oninput"
                      @bind:after="MarkChanged"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" disabled="@(!_hasChanges || _saving)" @onclick="SaveAsync">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" disabled="@(!_hasChanges)" @onclick="Discard">
                Discard Changes
            </button>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <label class="form-label fw-semibold">Avatar Preview</label>
                @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                {
                    <div class="mb-2">
                        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle"
                             style="width:120px;height:120px;object-fit:cover;" />
                    </div>
                }
                else
                {
                    <div class="mb-2 bg-secondary-subtle rounded-circle d-inline-flex align-items-center justify-content-center"
                         style="width:120px;height:120px;">
                        <span class="text-muted fs-1">?</span>
                    </div>
                }
                <div class="mt-2">
                    <small class="text-muted text-break">@_avatarUrl</small>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private bool _hasChanges;
    private bool _showSuccess;
    private bool _saving;
    private UserProfile? _lastProfile;

    protected override void OnParametersSet()
    {
        if (Profile is not null && Profile != _lastProfile)
        {
            _lastProfile = Profile;
            ResetToSaved();
        }
    }

    private void ResetToSaved()
    {
        if (_lastProfile is null) return;
        _displayName = _lastProfile.DisplayName;
        _email = _lastProfile.Email;
        _bio = _lastProfile.Bio;
        _avatarUrl = _lastProfile.AvatarUrl;
        _hasChanges = false;
        _showSuccess = false;
    }

    private void MarkChanged()
    {
        _hasChanges = true;
        _showSuccess = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await OnSave.InvokeAsync(updated);
        _lastProfile = updated;
        _hasChanges = false;
        _showSuccess = true;
        _saving = false;
    }

    private void Discard() => ResetToSaved();
}

@using sv_6db0c24234034a40aab2695891c22120.Services

<h4 class="mb-4">Notification Preferences</h4>

@if (_showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Preferences saved successfully!
        <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
    </div>
}

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Notification Toggles</h6>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@_emailNotifications"
                   @onchange="e => { _emailNotifications = (bool)e.Value!; }" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@_pushNotifications"
                   @onchange="e => { _pushNotifications = (bool)e.Value!; }" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@_weeklyDigest"
                   @onchange="e => { _weeklyDigest = (bool)e.Value!; }" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Channel Muting</h6>
        <p class="text-muted small">Muted channels will not send notifications.</p>

        @foreach (var channel in _allChannels)
        {
            var ch = channel;
            var isMuted = _mutedChannels.Contains(ch);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(ch, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{ch}")">
                    @ch
                    @if (isMuted)
                    {
                        <span class="badge bg-secondary ms-2">Muted</span>
                    }
                </label>
            </div>
        }
    </div>
</div>

<button class="btn btn-primary" disabled="@_saving" @onclick="SaveAsync">
    @if (_saving)
    {
        <span class="spinner-border spinner-border-sm me-1"></span>
    }
    Save Preferences
</button>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private bool _showSuccess;
    private bool _saving;

    private static readonly string[] _allChannels =
        ["general", "announcements", "marketing", "engineering", "design", "support"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest,
            _mutedChannels.ToList());
        await OnSave.InvokeAsync(updated);
        _showSuccess = true;
        _saving = false;
    }
}

@using sv_6db0c24234034a40aab2695891c22120.Services

<h4 class="mb-4">Appearance</h4>

@if (_showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Appearance settings saved!
        <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
    </div>
}

<div class="row">
    <div class="col-md-7">
        <div class="card mb-3">
            <div class="card-body">
                <h6 class="card-title">Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    var t = theme;
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
                               checked="@(_theme == t)"
                               @onchange="() => _theme = t" />
                        <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-body">
                <h6 class="card-title">Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    var s = size;
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{s}")"
                               checked="@(_fontSize == s)"
                               @onchange="() => _fontSize = s" />
                        <label class="form-check-label" for="@($"fs-{s}")">@s</label>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-body">
                <h6 class="card-title">Language</h6>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-body">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)e.Value!" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>
        </div>

        <button class="btn btn-primary" disabled="@_saving" @onclick="SaveAsync">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save
        </button>
    </div>

    <div class="col-md-5">
        <div class="card">
            <div class="card-header">
                <h6 class="mb-0">Live Preview</h6>
            </div>
            <div class="card-body @PreviewBgClass" style="@PreviewStyle min-height:200px; transition: all 0.2s;">
                <h6 class="@PreviewTextClass" style="@PreviewFontStyle">Dashboard</h6>
                <p class="@PreviewTextClass @(_compactMode ? "mb-1" : "mb-3")" style="@PreviewFontStyle">
                    This is a preview of your appearance settings.
                </p>
                <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                    <span class="badge @PreviewBadgeClass">Badge</span>
                    <span class="badge @PreviewBadgeClass">Label</span>
                </div>
                <button class="btn btn-sm @PreviewButtonClass" disabled>Sample Button</button>

                <hr class="@PreviewTextClass" />
                <small class="@PreviewMutedClass" style="@PreviewFontStyle">
                    Theme: @_theme · Font: @_fontSize · Lang: @_language · Compact: @(_compactMode ? "On" : "Off")
                </small>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _showSuccess;
    private bool _saving;

    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private string PreviewBgClass => _theme switch
    {
        "Dark" => "bg-dark",
        _ => "bg-light"
    };

    private string PreviewTextClass => _theme switch
    {
        "Dark" => "text-light",
        _ => "text-dark"
    };

    private string PreviewMutedClass => _theme switch
    {
        "Dark" => "text-light opacity-50",
        _ => "text-muted"
    };

    private string PreviewBadgeClass => _theme switch
    {
        "Dark" => "bg-light text-dark",
        _ => "bg-dark text-light"
    };

    private string PreviewButtonClass => _theme switch
    {
        "Dark" => "btn-outline-light",
        _ => "btn-outline-dark"
    };

    private string PreviewStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.15rem;",
        _ => "font-size:1rem;"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.15rem;",
        _ => "font-size:1rem;"
    };

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _showSuccess = true;
        _saving = false;
    }
}

