@using sv_6db0c24234034a40aab2695891c22120.Services

<h4 class="mb-4">Notification Preferences</h4>

@if (_showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Preferences saved successfully!
        <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
    </div>
}

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Notification Toggles</h6>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@_emailNotifications"
                   @onchange="e => { _emailNotifications = (bool)e.Value!; }" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@_pushNotifications"
                   @onchange="e => { _pushNotifications = (bool)e.Value!; }" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@_weeklyDigest"
                   @onchange="e => { _weeklyDigest = (bool)e.Value!; }" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Channel Muting</h6>
        <p class="text-muted small">Muted channels will not send notifications.</p>

        @foreach (var channel in _allChannels)
        {
            var ch = channel;
            var isMuted = _mutedChannels.Contains(ch);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(ch, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{ch}")">
                    @ch
                    @if (isMuted)
                    {
                        <span class="badge bg-secondary ms-2">Muted</span>
                    }
                </label>
            </div>
        }
    </div>
</div>

<button class="btn btn-primary" disabled="@_saving" @onclick="SaveAsync">
    @if (_saving)
    {
        <span class="spinner-border spinner-border-sm me-1"></span>
    }
    Save Preferences
</button>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private bool _showSuccess;
    private bool _saving;

    private static readonly string[] _allChannels =
        ["general", "announcements", "marketing", "engineering", "design", "support"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest,
            _mutedChannels.ToList());
        await OnSave.InvokeAsync(updated);
        _showSuccess = true;
        _saving = false;
    }
}

