@using sv_6db0c24234034a40aab2695891c22120.Services

<h4 class="mb-4">Appearance</h4>

@if (_showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Appearance settings saved!
        <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
    </div>
}

<div class="row">
    <div class="col-md-7">
        <div class="card mb-3">
            <div class="card-body">
                <h6 class="card-title">Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    var t = theme;
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
                               checked="@(_theme == t)"
                               @onchange="() => _theme = t" />
                        <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-body">
                <h6 class="card-title">Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    var s = size;
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{s}")"
                               checked="@(_fontSize == s)"
                               @onchange="() => _fontSize = s" />
                        <label class="form-check-label" for="@($"fs-{s}")">@s</label>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-body">
                <h6 class="card-title">Language</h6>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-body">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)e.Value!" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>
        </div>

        <button class="btn btn-primary" disabled="@_saving" @onclick="SaveAsync">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save
        </button>
    </div>

    <div class="col-md-5">
        <div class="card">
            <div class="card-header">
                <h6 class="mb-0">Live Preview</h6>
            </div>
            <div class="card-body @PreviewBgClass" style="@PreviewStyle min-height:200px; transition: all 0.2s;">
                <h6 class="@PreviewTextClass" style="@PreviewFontStyle">Dashboard</h6>
                <p class="@PreviewTextClass @(_compactMode ? "mb-1" : "mb-3")" style="@PreviewFontStyle">
                    This is a preview of your appearance settings.
                </p>
                <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                    <span class="badge @PreviewBadgeClass">Badge</span>
                    <span class="badge @PreviewBadgeClass">Label</span>
                </div>
                <button class="btn btn-sm @PreviewButtonClass" disabled>Sample Button</button>

                <hr class="@PreviewTextClass" />
                <small class="@PreviewMutedClass" style="@PreviewFontStyle">
                    Theme: @_theme · Font: @_fontSize · Lang: @_language · Compact: @(_compactMode ? "On" : "Off")
                </small>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _showSuccess;
    private bool _saving;

    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private string PreviewBgClass => _theme switch
    {
        "Dark" => "bg-dark",
        _ => "bg-light"
    };

    private string PreviewTextClass => _theme switch
    {
        "Dark" => "text-light",
        _ => "text-dark"
    };

    private string PreviewMutedClass => _theme switch
    {
        "Dark" => "text-light opacity-50",
        _ => "text-muted"
    };

    private string PreviewBadgeClass => _theme switch
    {
        "Dark" => "bg-light text-dark",
        _ => "bg-dark text-light"
    };

    private string PreviewButtonClass => _theme switch
    {
        "Dark" => "btn-outline-light",
        _ => "btn-outline-dark"
    };

    private string PreviewStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.15rem;",
        _ => "font-size:1rem;"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.15rem;",
        _ => "font-size:1rem;"
    };

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _showSuccess = true;
        _saving = false;
    }
}

