@using sv_6db0c24234034a40aab2695891c22120.Services

<div class="card">
    <div class="card-header">
        <h6 class="mb-0">Active Sessions</h6>
    </div>
    <div class="card-body p-0">
        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (Sessions is not null)
                    {
                        @foreach (var session in Sessions)
                        {
                            var isCurrentSession = session.Id == CurrentSessionId;
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrentSession)
                                    {
                                        <span class="badge bg-success ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td class="text-end">
                                    @if (!isCurrentSession)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@* Revoke confirmation dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5);">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@_sessionToRevoke.Device</strong> in
                        <strong>@_sessionToRevoke.Location</strong>?
                    </p>
                    <p class="text-muted small">This will sign out that device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" disabled="@_revoking" @onclick="ConfirmRevokeAsync">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        _revoking = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_6db0c24234034a40aab2695891c22120.Services

<h4 class="mb-4">Security</h4>

<ChangePasswordPanel OnChangePassword="HandleChangePasswordAsync" />

<div class="card mb-4">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <small class="text-muted">
                    @if (Security?.TwoFactorEnabled == true)
                    {
                        <span class="text-success">● Enabled</span>
                    }
                    else
                    {
                        <span class="text-danger">● Disabled</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@_twoFactorEnabled"
                       @onchange="e => { _twoFactorEnabled = (bool)e.Value!; }" />
            </div>
        </div>

        @if (Security?.LastPasswordChange.HasValue == true)
        {
            <hr />
            <small class="text-muted">
                Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </small>
        }
    </div>
</div>

<ActiveSessionsTable Sessions="@Security?.Sessions"
                     CurrentSessionId="@CurrentSessionId"
                     OnRevoke="OnRevokeSession" />

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool _twoFactorEnabled;

    protected override void OnParametersSet()
    {
        if (Security is not null)
        {
            _twoFactorEnabled = Security.TwoFactorEnabled;
        }
    }

    private async Task HandleChangePasswordAsync((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }
}

@page "/settings"
@rendermode InteractiveServer
@using sv_6db0c24234034a40aab2695891c22120.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<h2 class="mb-4">Settings</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3 col-lg-2 mb-4">
            <SettingsSidebar ActiveSection="@_activeSection"
                            OnSectionChanged="section => _activeSection = section" />
        </div>

        <div class="col-md-9 col-lg-10">
            @switch (_activeSection)
            {
                case "profile":
                    <ProfileSection Profile="@_profile" OnSave="SaveProfileAsync" />
                    break;

                case "notifications":
                    <NotificationsSection Prefs="@_notificationPrefs"
                                          OnSave="SaveNotificationPrefsAsync" />
                    break;

                case "security":
                    <SecuritySection Security="@_security"
                                     CurrentSessionId="@_currentSessionId"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnRevokeSession="RevokeSessionAsync" />
                    break;

                case "appearance":
                    <AppearanceSection Settings="@_appearance"
                                       OnSave="SaveAppearanceAsync" />
                    break;
            }
        </div>
    </div>
}

@code {
    private string _activeSection = "profile";
    private bool _loading = true;
    private string _currentSessionId = "sess-1";

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
